class Engine:
    A_CELLS = [(0,0),(0,1),(0,2),(1,2),(2,2)]
    B_CELLS = [(0,0),(0,1),(0,2),(1,0),(2,0)]
    def __init__(self):
        self.state = {'levels': 0, 'count': 0, 'A': [15,18], 'B': [15,36], 'hist': []}
        self._build_base()
    def _build_base(self):
        b = np.full((64,64), 9, dtype=int)
        b[0:63, 30:33] = 10
        b[45:48, 51:60] = 11
        b[48:54, 51:54] = 11
        b[:, 63] = 11
        b[63, 0:63] = 5
        self.base = b
    def reset(self):
        self.state['A'] = [15,18]
        self.state['B'] = [15,36]
        self.state['hist'] = []
        self.state['count'] = 0
        self.state['levels'] = 0
        self._build_base()
        return self._render()
    def _clamp(self, p):
        p[0] = max(0, min(55, p[0]))
        p[1] = max(0, min(55, p[1]))
    def step(self, action):
        kind = action[0]
        A = self.state['A']; B = self.state['B']
        if kind in (1,2,3,4):
            self.state['hist'].append((list(A), list(B)))
            if kind == 1:
                A[0]-=3; B[0]-=3
            elif kind == 2:
                A[0]+=3; B[0]+=3
            elif kind == 3:
                A[1]-=3; B[1]+=3
            elif kind == 4:
                A[1]+=3; B[1]-=3
            self._clamp(A); self._clamp(B)
            self.state['count'] += 1
        elif kind == 5:
            self.state['count'] += 1
        elif kind == 7:
            if self.state['hist']:
                pa, pb = self.state['hist'].pop()
                self.state['A'] = pa; self.state['B'] = pb
        return self._render()
    def _render(self):
        g = self.base.copy()
        k = min(self.state['count'], 63)
        if k > 0:
            g[0:k, 63] = 5
        ref = g.copy()
        br, bc = self.state['B']
        for (cr, cc) in self.B_CELLS:
            r0 = br+3*cr; c0 = bc+3*cc
            g[r0:r0+3, c0:c0+3] = 4
        ar, ac = self.state['A']
        for (cr, cc) in self.A_CELLS:
            r0 = ar+3*cr; c0 = ac+3*cc
            g[r0:r0+3, c0:c0+3] = 5
            hr = r0+1; hc = c0+1
            v = ref[hr, hc]
            g[hr, hc] = v if v != 9 else 0
        return g
    def is_win(self, prev_frame):
        return self.state.get('levels', 0) > 0
